<?php
namespace App\Domain\Inventory\Instances\Refinement;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\RefinementStatModifier;use InvalidArgumentException;
final class RefinementStatModifierValidator{public function validate(RefinementStatModifier $modifier){$level=(int)$modifier->refinement_level;$points=(int)$modifier->stat_increase_basis_points;if($level<RefinementStatModifierLimits::MIN_LEVEL||$level>RefinementStatModifierLimits::MAX_LEVEL)throw new InvalidArgumentException('Refinement modifier level must be between 1 and 15.');if($points<RefinementStatModifierLimits::MIN_BASIS_POINTS||$points>RefinementStatModifierLimits::MAX_BASIS_POINTS)throw new InvalidArgumentException('Refinement modifier basis points are outside the supported range.');if(!in_array($modifier->status,CatalogStatus::values(),true))throw new InvalidArgumentException('Invalid refinement modifier status.');return$modifier;}}
